import { useState, useRef, useEffect, useCallback } from 'react';
import { useSearchParams } from 'react-router-dom';
import { generateTartan, generateVariations, DEFAULT_CONSTRAINTS, CONSTRAINT_PRESETS } from '../core/generator';
import { parseThreadcount, toThreadcountString, generateSignatures } from '../core/sett';
import { breedTartans } from '../core/breeding';
import { renderTartanToCanvas } from '../utils/renderTartan';
import type { GeneratorResult, GeneratorConstraints, WeaveType } from '../core/types';
import WeaveSelector from '../components/WeaveSelector';

const BATCH_SIZE = 9;

// ---------------------------------------------------------------------------
// Swatch card (used in batch grid, history, saved, offspring)
// ---------------------------------------------------------------------------

function SwatchCard({
  result,
  size = 240,
  isActive = false,
  isSelected = false,
  onClick,
  label,
  className = '',
}: {
  result: GeneratorResult;
  size?: number;
  isActive?: boolean;
  isSelected?: boolean;
  onClick: () => void;
  label?: string;
  className?: string;
}) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [rendered, setRendered] = useState(false);
  const tc = toThreadcountString(result.sett);

  useEffect(() => {
    if (canvasRef.current) {
      renderTartanToCanvas(canvasRef.current, tc, size);
      setRendered(true);
    }
  }, [tc, size]);

  return (
    <button onClick={onClick} className={`group relative ${className}`}>
      <div className={`w-full aspect-square rounded-lg overflow-hidden border-2 transition-all duration-200
        ${isSelected
          ? 'border-pink-500 shadow-lg ring-2 ring-pink-500/20'
          : isActive
            ? 'border-[var(--accent)] shadow-lg ring-2 ring-[var(--accent)]/20 scale-[1.02]'
            : 'border-[var(--border)] group-hover:border-[var(--border-hover)] group-hover:shadow-md group-hover:-translate-y-0.5'
        }`}>
        {!rendered && <div className="w-full h-full bg-[var(--border)] animate-pulse" />}
        <canvas
          ref={canvasRef}
          className={`w-full h-full ${rendered ? '' : 'opacity-0 absolute'}`}
          style={{ imageRendering: 'pixelated' }}
        />
      </div>
      {label && (
        <span className="block mt-1 text-[10px] text-[var(--text-tertiary)] text-center font-mono truncate">
          {label}
        </span>
      )}
    </button>
  );
}

// ---------------------------------------------------------------------------
// Active tartan detail sidebar
// ---------------------------------------------------------------------------

function DetailSidebar({
  result,
  weave,
  onWeaveChange,
  onMutate,
  mutations,
  onPromoteMutation,
  mutationType,
  onMutationTypeChange,
  onSave,
  isSaved,
}: {
  result: GeneratorResult;
  weave: WeaveType;
  onWeaveChange: (w: WeaveType) => void;
  onMutate: () => void;
  mutations: GeneratorResult[];
  onPromoteMutation: (r: GeneratorResult) => void;
  mutationType: 'colors' | 'proportions' | 'both';
  onMutationTypeChange: (t: 'colors' | 'proportions' | 'both') => void;
  onSave: () => void;
  isSaved: boolean;
}) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const tc = toThreadcountString(result.sett);

  useEffect(() => {
    if (canvasRef.current) {
      renderTartanToCanvas(canvasRef.current, tc, 600, weave);
    }
  }, [tc, weave]);

  return (
    <div className="space-y-5 lg:sticky lg:top-20 lg:self-start">
      {/* Large preview */}
      <div className="rounded-xl overflow-hidden border border-[var(--border)] bg-[var(--bg-card)] shadow-sm">
        <canvas
          ref={canvasRef}
          className="w-full aspect-square"
          style={{ imageRendering: 'pixelated' }}
        />
      </div>

      {/* Save + thread count */}
      <div className="flex items-start gap-3">
        <div className="flex-1 bg-[var(--bg-card)] border border-[var(--border)] rounded-lg
                       px-3 py-2 text-xs font-mono text-[var(--text-secondary)]
                       break-all leading-relaxed select-all min-h-[2.5rem]">
          {tc}
        </div>
        <button
          onClick={onSave}
          className={`px-3 py-2 rounded-lg text-xs font-medium border transition-all
            ${isSaved
              ? 'bg-[var(--accent)] text-white border-[var(--accent)]'
              : 'border-[var(--border)] text-[var(--text-secondary)] hover:border-[var(--accent)] hover:text-[var(--accent)]'
            }`}
          title={isSaved ? 'Saved' : 'Save this tartan'}
        >
          {isSaved ? '★' : '☆'}
        </button>
      </div>

      {/* Weave selector */}
      <WeaveSelector threadcount={tc} activeWeave={weave} onChange={onWeaveChange} />

      {/* Mutate section */}
      <div className="space-y-3 border-t border-[var(--border)] pt-4">
        <span className="text-[10px] font-mono uppercase tracking-widest text-[var(--text-tertiary)]">
          Mutate (single parent)
        </span>
        <div className="flex gap-2 flex-wrap">
          {(['colors', 'proportions', 'both'] as const).map((mt) => (
            <button
              key={mt}
              onClick={() => onMutationTypeChange(mt)}
              className={`pill text-xs capitalize
                ${mutationType === mt ? 'pill-active' : 'pill-inactive'}`}
            >
              {mt}
            </button>
          ))}
          <button onClick={onMutate} className="pill text-xs pill-active ml-auto">
            Mutate ×8
          </button>
        </div>

        {mutations.length > 0 && (
          <>
            <div className="flex gap-2 overflow-x-auto no-scrollbar pb-1 -mx-1 px-1">
              {mutations.map((r, i) => (
                <SwatchCard
                  key={`mut-${r.seed}-${i}`}
                  result={r}
                  size={160}
                  onClick={() => onPromoteMutation(r)}
                  className="flex-shrink-0 w-20 sm:w-24"
                />
              ))}
            </div>
            <p className="text-[10px] text-[var(--text-tertiary)]">
              Tap a mutation to replace the selected swatch
            </p>
          </>
        )}
      </div>
    </div>
  );
}

// ---------------------------------------------------------------------------
// Main page
// ---------------------------------------------------------------------------

export default function GeneratePage() {
  const [searchParams] = useSearchParams();

  // Core state
  const [batch, setBatch] = useState<GeneratorResult[]>([]);
  const [activeIndex, setActiveIndex] = useState(0);
  const [weave, setWeave] = useState<WeaveType>('twill-2-2');

  // Constraints
  const [preset, setPreset] = useState<string>('classic');
  const [constraints, setConstraints] = useState<GeneratorConstraints>({
    ...DEFAULT_CONSTRAINTS,
    ...CONSTRAINT_PRESETS['classic'],
  });

  // Mutation
  const [mutations, setMutations] = useState<GeneratorResult[]>([]);
  const [mutationType, setMutationType] = useState<'colors' | 'proportions' | 'both'>('colors');

  // Breeding (two-parent crossover)
  const [breedMode, setBreedMode] = useState(false);
  const [breedParents, setBreedParents] = useState<[number | null, number | null]>([null, null]);
  const [offspring, setOffspring] = useState<GeneratorResult[]>([]);

  // History + saved
  const [history, setHistory] = useState<GeneratorResult[]>([]);
  const [saved, setSaved] = useState<GeneratorResult[]>(() => {
    try {
      const raw = localStorage.getItem('tartanism-saved');
      if (raw) return JSON.parse(raw);
    } catch {}
    return [];
  });
  const [showHistory, setShowHistory] = useState(false);
  const [showSaved, setShowSaved] = useState(false);

  // Persist saved to localStorage
  useEffect(() => {
    try { localStorage.setItem('tartanism-saved', JSON.stringify(saved)); } catch {}
  }, [saved]);

  const passedTc = searchParams.get('tc');

  // Auto-generate on mount
  useEffect(() => {
    if (passedTc) {
      try {
        const sett = parseThreadcount(passedTc);
        const signature = generateSignatures(sett);
        const result: GeneratorResult = { sett, seed: 0, constraints, signature };
        setBatch([result]);
        setActiveIndex(0);
      } catch { generateBatch(); }
    } else {
      generateBatch();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const activeResult = batch[activeIndex] || null;

  function generateBatch() {
    const results: GeneratorResult[] = [];
    for (let i = 0; i < BATCH_SIZE; i++) {
      results.push(generateTartan(constraints));
    }
    setBatch(results);
    setActiveIndex(0);
    setMutations([]);
    setOffspring([]);
    setBreedMode(false);
    setBreedParents([null, null]);
    // Add to history
    setHistory(prev => [...results, ...prev].slice(0, 100));
  }

  function mutateActive() {
    if (!activeResult) return;
    try {
      const results = generateVariations(
        activeResult.sett, 8, mutationType,
        Math.floor(Math.random() * 2147483647)
      );
      setMutations(results);
    } catch {}
  }

  function promoteMutation(result: GeneratorResult) {
    setBatch(prev => {
      const next = [...prev];
      next[activeIndex] = result;
      return next;
    });
    setMutations([]);
    setHistory(prev => [result, ...prev].slice(0, 100));
  }

  function toggleSave() {
    if (!activeResult) return;
    const tc = toThreadcountString(activeResult.sett);
    const idx = saved.findIndex(s => toThreadcountString(s.sett) === tc);
    if (idx >= 0) {
      setSaved(prev => prev.filter((_, i) => i !== idx));
    } else {
      setSaved(prev => [activeResult, ...prev]);
    }
  }

  const isSaved = activeResult
    ? saved.some(s => toThreadcountString(s.sett) === toThreadcountString(activeResult.sett))
    : false;

  // Breeding
  function toggleBreedMode() {
    if (breedMode) {
      setBreedMode(false);
      setBreedParents([null, null]);
      setOffspring([]);
    } else {
      setBreedMode(true);
      setBreedParents([activeIndex, null]);
      setOffspring([]);
    }
  }

  function handleBreedSelect(index: number) {
    if (!breedMode) return;
    if (breedParents[0] === null) {
      setBreedParents([index, null]);
    } else if (breedParents[0] === index) {
      // Deselect
      setBreedParents([null, null]);
    } else {
      // Second parent selected, breed
      setBreedParents([breedParents[0], index]);
      const p1 = batch[breedParents[0]];
      const p2 = batch[index];
      if (p1 && p2) {
        const results = breedTartans(p1.sett, p2.sett, 8);
        setOffspring(results);
        setHistory(prev => [...results, ...prev].slice(0, 100));
      }
    }
  }

  function promoteOffspring(result: GeneratorResult) {
    // Add offspring to the batch, replacing least recently touched slot
    setBatch(prev => [...prev, result]);
    setHistory(prev => [result, ...prev].slice(0, 100));
  }

  function rebreed() {
    if (breedParents[0] !== null && breedParents[1] !== null) {
      const p1 = batch[breedParents[0]];
      const p2 = batch[breedParents[1]];
      if (p1 && p2) {
        const results = breedTartans(p1.sett, p2.sett, 8);
        setOffspring(results);
        setHistory(prev => [...results, ...prev].slice(0, 100));
      }
    }
  }

  const handlePresetChange = useCallback((newPreset: string) => {
    setPreset(newPreset);
    if (CONSTRAINT_PRESETS[newPreset]) {
      setConstraints({ ...DEFAULT_CONSTRAINTS, ...CONSTRAINT_PRESETS[newPreset] });
    }
  }, []);

  const handleRangeChange = useCallback((
    key: 'colorCount' | 'stripeCount' | 'threadCount' | 'totalThreads',
    bound: 'min' | 'max',
    value: number
  ) => {
    setConstraints((prev) => ({
      ...prev,
      [key]: { ...prev[key], [bound]: value },
    }));
    setPreset('custom');
  }, []);

  return (
    <div className="min-h-screen">
      <div className="max-w-6xl mx-auto px-4 sm:px-6 py-4 sm:py-8">

        {/* Header row */}
        <div className="flex items-start justify-between flex-wrap gap-3 mb-5">
          <div>
            <h1 className="text-2xl sm:text-3xl font-serif font-normal text-[var(--text)]">
              Generate
            </h1>
            <p className="text-sm text-[var(--text-secondary)] mt-0.5">
              {BATCH_SIZE} per batch. Select, mutate, breed, save.
            </p>
          </div>
          <div className="flex gap-2">
            <button
              onClick={toggleBreedMode}
              className={`px-4 py-2 rounded-lg text-sm font-medium transition-all duration-200 active:scale-[0.98]
                ${breedMode
                  ? 'bg-pink-500 text-white'
                  : 'border border-[var(--border)] text-[var(--text-secondary)] hover:border-pink-400 hover:text-pink-500'
                }`}
            >
              {breedMode ? 'Cancel breed' : 'Breed two'}
            </button>
            <button
              onClick={generateBatch}
              className="px-5 py-2 rounded-lg text-sm font-medium
                         bg-[var(--accent)] text-white
                         hover:opacity-90 transition-all duration-200
                         active:scale-[0.98]"
            >
              New batch
            </button>
          </div>
        </div>

        {/* Breed mode banner */}
        {breedMode && (
          <div className="bg-pink-50 border border-pink-200 rounded-lg px-4 py-3 mb-5 text-sm text-pink-800">
            {breedParents[1] !== null
              ? `Parents selected. ${offspring.length} offspring generated below.`
              : breedParents[0] !== null
                ? 'Parent 1 selected (pink border). Tap a second tartan to breed.'
                : 'Tap two tartans to select parents for crossover breeding.'
            }
          </div>
        )}

        {/* Presets */}
        <div className="flex gap-2 flex-wrap items-center mb-4">
          <span className="text-[10px] font-mono uppercase tracking-widest text-[var(--text-tertiary)] mr-1">
            Style
          </span>
          {['simple', 'classic', 'complex', 'minimal', 'hunting', 'dress'].map((p) => (
            <button
              key={p}
              onClick={() => handlePresetChange(p)}
              className={`pill text-xs capitalize ${preset === p ? 'pill-active' : 'pill-inactive'}`}
            >
              {p}
            </button>
          ))}
        </div>

        {/* Constraints */}
        <details className="mb-6">
          <summary className="text-xs text-[var(--text-secondary)] cursor-pointer mb-3 select-none">
            Adjust constraints
          </summary>
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
            <RangeControl label="Colors" min={constraints.colorCount.min} max={constraints.colorCount.max}
              absMin={2} absMax={8}
              onMinChange={(v) => handleRangeChange('colorCount', 'min', v)}
              onMaxChange={(v) => handleRangeChange('colorCount', 'max', v)} />
            <RangeControl label="Stripes" min={constraints.stripeCount.min} max={constraints.stripeCount.max}
              absMin={2} absMax={16}
              onMinChange={(v) => handleRangeChange('stripeCount', 'min', v)}
              onMaxChange={(v) => handleRangeChange('stripeCount', 'max', v)} />
            <RangeControl label="Per stripe" min={constraints.threadCount.min} max={constraints.threadCount.max}
              absMin={2} absMax={64}
              onMinChange={(v) => handleRangeChange('threadCount', 'min', v)}
              onMaxChange={(v) => handleRangeChange('threadCount', 'max', v)} />
            <RangeControl label="Total" min={constraints.totalThreads.min} max={constraints.totalThreads.max}
              absMin={20} absMax={400}
              onMinChange={(v) => handleRangeChange('totalThreads', 'min', v)}
              onMaxChange={(v) => handleRangeChange('totalThreads', 'max', v)} />
          </div>
        </details>

        {/* Main layout: grid + sidebar */}
        <div className="grid grid-cols-1 lg:grid-cols-[1fr_320px] gap-6">

          {/* Batch grid */}
          <div className="space-y-6">
            <div className="grid grid-cols-3 gap-2 sm:gap-3">
              {batch.map((result, i) => (
                <SwatchCard
                  key={`batch-${result.seed}-${i}`}
                  result={result}
                  size={240}
                  isActive={!breedMode && i === activeIndex}
                  isSelected={breedMode && (breedParents[0] === i || breedParents[1] === i)}
                  onClick={() => {
                    if (breedMode) {
                      handleBreedSelect(i);
                    } else {
                      setActiveIndex(i);
                      setMutations([]);
                    }
                  }}
                />
              ))}
            </div>

            {/* Offspring from breeding */}
            {offspring.length > 0 && (
              <div className="space-y-3">
                <div className="flex items-center justify-between">
                  <span className="text-[10px] font-mono uppercase tracking-widest text-[var(--text-tertiary)]">
                    Offspring ({offspring.length})
                  </span>
                  <button onClick={rebreed} className="text-xs text-pink-500 hover:underline font-medium">
                    Breed again
                  </button>
                </div>
                <div className="grid grid-cols-4 gap-2">
                  {offspring.map((r, i) => (
                    <SwatchCard
                      key={`off-${r.seed}-${i}`}
                      result={r}
                      size={160}
                      onClick={() => promoteOffspring(r)}
                      label={['interleave', 'P1+P2 colors', 'P2+P1 colors', 'random mix'][i % 4]}
                    />
                  ))}
                </div>
                <p className="text-[10px] text-[var(--text-tertiary)]">
                  Tap offspring to add to the grid. Each uses a different crossover strategy.
                </p>
              </div>
            )}

            {/* History + Saved toggles */}
            <div className="flex gap-3 border-t border-[var(--border)] pt-4">
              <button
                onClick={() => { setShowHistory(!showHistory); setShowSaved(false); }}
                className={`text-xs font-medium transition-colors ${showHistory ? 'text-[var(--accent)]' : 'text-[var(--text-secondary)] hover:text-[var(--text)]'}`}
              >
                History ({history.length})
              </button>
              <button
                onClick={() => { setShowSaved(!showSaved); setShowHistory(false); }}
                className={`text-xs font-medium transition-colors ${showSaved ? 'text-[var(--accent)]' : 'text-[var(--text-secondary)] hover:text-[var(--text)]'}`}
              >
                ★ Saved ({saved.length})
              </button>
            </div>

            {/* History grid */}
            {showHistory && history.length > 0 && (
              <div className="space-y-2">
                <div className="grid grid-cols-5 sm:grid-cols-8 gap-1.5">
                  {history.map((r, i) => (
                    <SwatchCard
                      key={`hist-${r.seed}-${i}`}
                      result={r}
                      size={120}
                      onClick={() => {
                        setBatch(prev => {
                          const next = [...prev];
                          next[activeIndex] = r;
                          return next;
                        });
                        setShowHistory(false);
                      }}
                      className="w-full"
                    />
                  ))}
                </div>
                <p className="text-[10px] text-[var(--text-tertiary)]">
                  Tap to load into current slot. Last {history.length} generated.
                </p>
              </div>
            )}

            {/* Saved grid */}
            {showSaved && (
              <div className="space-y-2">
                {saved.length === 0 ? (
                  <p className="text-sm text-[var(--text-tertiary)] py-8 text-center">
                    No saved tartans yet. Use the ★ button to save.
                  </p>
                ) : (
                  <div className="grid grid-cols-4 sm:grid-cols-6 gap-2">
                    {saved.map((r, i) => (
                      <SwatchCard
                        key={`saved-${r.seed}-${i}`}
                        result={r}
                        size={160}
                        onClick={() => {
                          setBatch(prev => {
                            const next = [...prev];
                            next[activeIndex] = r;
                            return next;
                          });
                          setShowSaved(false);
                        }}
                        className="w-full"
                      />
                    ))}
                  </div>
                )}
                <p className="text-[10px] text-[var(--text-tertiary)]">
                  Saved tartans persist across sessions. Tap to load.
                </p>
              </div>
            )}
          </div>

          {/* Detail sidebar */}
          {activeResult && !breedMode && (
            <DetailSidebar
              result={activeResult}
              weave={weave}
              onWeaveChange={setWeave}
              onMutate={mutateActive}
              mutations={mutations}
              onPromoteMutation={promoteMutation}
              mutationType={mutationType}
              onMutationTypeChange={setMutationType}
              onSave={toggleSave}
              isSaved={isSaved}
            />
          )}
        </div>
      </div>
    </div>
  );
}

// ---------------------------------------------------------------------------
// Range control with touch-friendly sizing
// ---------------------------------------------------------------------------

function RangeControl({
  label, min, max, absMin, absMax, onMinChange, onMaxChange,
}: {
  label: string; min: number; max: number; absMin: number; absMax: number;
  onMinChange: (v: number) => void; onMaxChange: (v: number) => void;
}) {
  return (
    <div className="bg-[var(--bg-card)] border border-[var(--border)] rounded-lg p-3">
      <label className="text-[10px] font-mono uppercase tracking-widest text-[var(--text-tertiary)] block mb-1">
        {label}
      </label>
      <div className="text-xs text-[var(--text-secondary)] mb-2 tabular-nums">{min} – {max}</div>
      <div className="space-y-3">
        <input type="range" min={absMin} max={absMax} value={min}
          onChange={(e) => onMinChange(Math.min(Number(e.target.value), max))}
          className="w-full h-2 bg-[var(--border)] rounded-full appearance-none cursor-pointer touch-pan-y
                     [&::-webkit-slider-thumb]:appearance-none [&::-webkit-slider-thumb]:w-5 [&::-webkit-slider-thumb]:h-5
                     [&::-webkit-slider-thumb]:rounded-full [&::-webkit-slider-thumb]:bg-[var(--accent)]
                     [&::-webkit-slider-thumb]:cursor-pointer [&::-webkit-slider-thumb]:shadow-md" />
        <input type="range" min={absMin} max={absMax} value={max}
          onChange={(e) => onMaxChange(Math.max(Number(e.target.value), min))}
          className="w-full h-2 bg-[var(--border)] rounded-full appearance-none cursor-pointer touch-pan-y
                     [&::-webkit-slider-thumb]:appearance-none [&::-webkit-slider-thumb]:w-5 [&::-webkit-slider-thumb]:h-5
                     [&::-webkit-slider-thumb]:rounded-full [&::-webkit-slider-thumb]:bg-[var(--accent)]
                     [&::-webkit-slider-thumb]:cursor-pointer [&::-webkit-slider-thumb]:shadow-md" />
      </div>
    </div>
  );
}
