/**
 * Tartan Breeding: crossover two parent setts to produce offspring.
 *
 * Four strategies:
 * 1. Interleave stripes from both parents
 * 2. Structure from P1, colors from P2
 * 3. Structure from P2, colors from P1
 * 4. Random mix with color swaps
 *
 * Ported from OldApp.tsx handleBreed().
 */

import { Sett, GeneratorResult, SettSignature } from './types';
import { parseThreadcount, generateSignatures } from './sett';
import { DEFAULT_CONSTRAINTS } from './generator';

export function breedTartans(p1: Sett, p2: Sett, count: number = 4): GeneratorResult[] {
  const offspring: GeneratorResult[] = [];
  const allColors = [...new Set([...p1.colors, ...p2.colors])];

  for (let i = 0; i < count; i++) {
    const childStripes: { color: string; count: number; isPivot?: boolean }[] = [];
    const seed = Date.now() + i + Math.floor(Math.random() * 10000);
    const strategy = i % 4;

    if (strategy === 0) {
      // Interleave
      const maxLen = Math.max(p1.stripes.length, p2.stripes.length);
      for (let j = 0; j < maxLen; j++) {
        if (j < p1.stripes.length && j % 2 === 0) {
          childStripes.push({ color: p1.stripes[j].color, count: p1.stripes[j].count });
        } else if (j < p2.stripes.length) {
          const s = p2.stripes[j % p2.stripes.length];
          childStripes.push({ color: s.color, count: s.count });
        }
      }
    } else if (strategy === 1) {
      // P1 structure, P2 colors
      p1.stripes.forEach((stripe, idx) => {
        childStripes.push({ color: p2.colors[idx % p2.colors.length], count: stripe.count });
      });
    } else if (strategy === 2) {
      // P2 structure, P1 colors
      p2.stripes.forEach((stripe, idx) => {
        childStripes.push({ color: p1.colors[idx % p1.colors.length], count: stripe.count });
      });
    } else {
      // Random mix
      const maxLen = Math.max(p1.stripes.length, p2.stripes.length);
      const rng = () => Math.random();
      for (let j = 0; j < maxLen; j++) {
        const parent = rng() > 0.5 ? p1 : p2;
        const s = parent.stripes[j % parent.stripes.length];
        const color = rng() > 0.7
          ? allColors[Math.floor(rng() * allColors.length)]
          : s.color;
        childStripes.push({ color, count: s.count });
      }
    }

    if (childStripes.length === 0) continue;

    // Mark pivots for symmetry
    childStripes[0].isPivot = true;
    childStripes[childStripes.length - 1].isPivot = true;

    const tc = childStripes
      .map(s => `${s.color}${s.isPivot ? '/' : ''}${s.count}`)
      .join(' ');

    try {
      const sett = parseThreadcount(tc);
      if (sett && sett.stripes.length > 0) {
        const signature = generateSignatures(sett);
        offspring.push({ sett, seed, constraints: DEFAULT_CONSTRAINTS, signature });
      }
    } catch {
      // Skip invalid offspring
    }
  }

  return offspring;
}
